mapper.select:
SELECT *
  FROM payment
 WHERE id = #{paymentId}
   AND user_id = #{userId}

SELECT EXISTS(
    SELECT 1
      FROM credit_transaction
     WHERE user_id = #{userId}
       AND type = 'AI_USAGE'
       AND amount < 0
       AND created_at >= #{paidAt}
)

SELECT EXISTS(
    SELECT 1
      FROM benefit_transaction
     WHERE user_id = #{userId}
       AND transaction_type = 'CONSUME'
       AND amount < 0
       AND created_at >= #{paidAt}
)

SELECT FROM refund_request rr JOIN payment p ON p.id = rr.payment_id JOIN users u ON u.id = rr.user_id
rr.status = #{status}
ORDER BY CASE WHEN rr.status = 'REQUESTED' THEN 0 ELSE 1 END, rr.id DESC
